const cbq = $input.first().json.callback_query;
const raw = cbq.data || '';
const parts = raw.split(':');
const action = parts[0];
const confirmation_id = parts.length > 1 ? parts[1] : '';
const extra = parts.length > 2 ? parts.slice(2).join(':') : '';

return [{
  json: {
    action,
    confirmation_id,
    extra,
    callback_query_id: cbq.id,
    chat_id: String(cbq.message.chat.id),
    user_id: String(cbq.from.id),
    message_id: cbq.message.message_id
  }
}];

const record = $('Delete Pending Record').first().json;
const payload = typeof record.payload === 'string' ? JSON.parse(record.payload) : record.payload;
return [{ json: { ...payload, command: record.command, confirmed: true } }];

const rec = $('Delete Pending Record').first().json;
const payload = typeof rec.payload === 'string' ? JSON.parse(rec.payload) : rec.payload;
const selectedDate = $('Extract Callback Data').first().json.extra;

return [{ json: {
  chat_id:  rec.chat_id  || payload.chat_id,
  user_id:  payload.user_id,
  username: payload.username,
  fullname: payload.fullname,
  lang:     rec.lang     || payload.lang,
  command:  'show',
  arg1:     selectedDate
} }];

